module IconHelper
  def lucide_icon(name, size: 20, **options)
    options[:class] = Array(options[:class]).join(" ")
    options[:aria] ||= { hidden: "true" }
    options[:width] = size
    options[:height] = size
    options[:viewBox] = "0 0 24 24"
    options[:fill] = "none"
    options[:stroke] = "currentColor"
    options[:"stroke-width"] = "2"
    options[:"stroke-linecap"] = "round"
    options[:"stroke-linejoin"] = "round"

    tag.svg(**options) { LUCIDE_PATHS.fetch(name.to_s).html_safe }
  end

